art_index":285,"end_index":397,"title":"What is Foundry Agent Service? - Microsoft Foundry"},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/overview?view=foundry-classic","start_index":602,"end_index":714,"title":"What is Foundry Agent Service? - Microsoft Foundry"},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/how-to/tools-classic/overview?view=foundry-classic","start_index":855,"end_index":988,"title":"What are tools in Foundry Agent Service - Microsoft Foundry"},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/overview?view=foundry-classic","start_index":1181,"end_index":1293,"title":"What is Foundry Agent Service? - Microsoft Foundry"},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/how-to/tools-classic/overview?view=foundry-classic","start_index":1432,"end_index":1565,"title":"What are tools in Foundry Agent Service - Microsoft Foundry"},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/how-to/tools-classic/overview?view=foundry-classic","start_index":1701,"end_index":1834,"title":"What are tools in Foundry Agent Service - Microsoft Foundry"},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/how-to/tools-classic/overview?view=foundry-classic","start_index":2006,"end_index":2139,"title":"What are tools in Foundry Agent Service - Microsoft Foundry"},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/how-to/tools-classic/bing-grounding?view=foundry-classic","start_index":2517,"end_index":2656,"title":"How to use Grounding with Bing Search in Foundry Agent Service ..."},{"type":"url_citation","url":"https://learn.microsoft.com/en-us/azure/ai-foundry/agents/how-to/tools-classic/bing-custom-search?view=foundry-classic","start_index":2885,"end_index":3028,"title":"How to use Custom Bing Search with